# Find all blocks of arabicSummary:`...`, and append arabicBody:`...`,
for panel_id, arb in translations.items():
    # Replace the matching arabicSummary to also include the arabicBody
    # We will just search for the id to be safe since text might have linebreaks
    pattern = re.compile(r"(id\s*:\s*"+str(panel_id)+r"\s*,.*?arabicSummary\s*:\s*`.*?`\s*,)", re.DOTALL)
    
    def repl(match):
        return match.group(1) + f"\n    arabicBody:`{arb}`,"

    content = pattern.sub(repl, content)

with open(file_path, "w", encoding="utf-8") as f:
    f.write(content)

